<?phpnamespace App\Http\Controllers;use App\Http\Controllers\Controller;use Illuminate\Support\Facades\Lang;use Illuminate\Support\Facades\Crypt;use Illuminate\Http\Request;use Auth;use Session;use DB;use Hash;use Validator;use Carbon\Carbon;use App\Helpers\InitHelp;class AreaController extends Controller{    protected $redirectTo = '/';    public function __construct()    {        //$this->middleware('guest', ['except' => ['logout']]);            }    public function index(Request $request)    {		        $data = array(            'title' => 'SETUP AREA',            'head' => 'Setup',            'classForm' => 'form-control form-control-sm',            'btnClass' => 'btn btn-primary btn-sm',            'classFormSelect2' => 'single-select select-2',			'can_insert' => hasPermission('area', 'tambah', Session::get('role')),            'can_update' => hasPermission('area', 'ubah', Session::get('role')),            'can_delete' => hasPermission('area', 'hapus', Session::get('role')),        );        return view('area.index', compact('data'));    }	    public function getData(Request $request)    {        $data = InitHelp::dataArea(2)->map(function ($row)        {            return ['id' => Crypt::encryptString($row->area_id) , 'nama' => $row->area_nama, 'status' => $row->area_status, ];        });		        return response()->json([			'status' => 'successful', 			'data' => $data,			'can_update' => hasPermission('area', 'ubah', Session::get('role')),            'can_delete' => hasPermission('area', 'hapus', Session::get('role')),		]);    }	    public function store(Request $request)    {        if ($request->ajax())        {            DB::beginTransaction();            try            {                $insert = DB::table('area')->insert(["area_id" => InitHelp::GetID('area', 'area_id') , "area_nama" => $request->area_nama, ]);                if ($insert)                {                    DB::commit();                    $msg = 'Data Berhasil Disimpan.';                    $status = 'success';                }                else                {                    $msg = 'Data Gagal Disimpan.';                    $status = 'error';                }                return response()->json(['status' => $status, 'message' => $msg, ]);            }            catch(\Throwable $e)            {                DB::rollback();                throw $e;                $msg = 'Data Gagal Disimpan';                $status = 'error';                return response()->json(['status' => $status, 'message' => $msg, ]);            }        }        else        {            return redirect('asset/');        }    }    public function update(Request $request)    {        if ($request->ajax())        {            DB::beginTransaction();            try            {                $update = DB::table('area')->where('area_id', Crypt::decryptString($request->id))                    ->update(["area_nama" => $request->area_nama, ]);                if ($update)                {                    DB::commit();                    $msg = 'Data Berhasil Diubah.';                    $status = 'success';                }                else                {                    $msg = 'Data Gagal Diubah.';                    $status = 'error';                }                return response()->json(['status' => $status, 'message' => $msg, ]);            }            catch(\Throwable $e)            {                DB::rollback();                throw $e;                $msg = 'Data Gagal Diubah';                $status = 'error';                return response()->json(['status' => $status, 'message' => $msg, ]);            }        }        else        {            return redirect('asset/');        }    }    public function destroy(Request $request, $id)    {        $cekArea = InitHelp::cekDataArea(Crypt::decryptString($request->id));        if (count($cekArea) == 0)        {            $query = DB::table('area')->where('area_id', Crypt::decryptString($request->id))                ->delete();            if ($query)            {                return response()->json(['status' => 'success', 'message' => 'Data Berhasil Dihapus']);            }            else            {                return response()                    ->json(['status' => 'error', 'message' => 'Data Tidak Ditemukan']);            }        }        else        {            return response()                ->json(['status' => 'error', 'message' => 'Gagal Hapus, Area Sudah Dipakai']);        }    }    public function NonAktif(Request $request)    {        if ($request->ajax())        {            DB::table('area')                ->where('area_id', Crypt::decryptString($request->id))                ->update(['area_status' => 'n', ]);            return response()                ->json(['status' => 'success']);        }        else        {            return response()                ->json(['status' => 'error']);        }    }    public function Aktif(Request $request)    {        if ($request->ajax())        {            DB::table('area')                ->where('area_id', Crypt::decryptString($request->id))                ->update(['area_status' => 'y', ]);            return response()                ->json(['status' => 'success']);        }        else        {            return response()                ->json(['status' => 'error']);        }    }    protected function guard()    {        return Auth::guard('web');    }}